    float luminance = dot(color, vec3(0.2126, 0.7152, 0.0722));

    // Increase saturation (using a simple saturation boost)
    vec3 saturatedColor = color * 1.5;

    // Add a bright additive term proportional to the original luminance
    float additiveGlow = luminance * 1.5;

    vec3 finalColor = saturatedColor + additiveGlow;

    gl_FragColor = vec4(clamp(finalColor, 0.0, 1.0), 1.0);
}

